104	// Calculate the time difference in milliseconds
105	double calculate_time_difference(struct timespec start, struct timespec end)
106	{
107	  double start_ms = start.tv_sec * 1000.0 + start.tv_nsec / 1000000.0;
108	  double end_ms = end.tv_sec * 1000.0 + end.tv_nsec / 1000000.0;
109	  return end_ms - start_ms;
110	}
