146	int split_time_stamp_and_convert_to_int(char time_stamp_str[], int shift, int length)
147	{
148	  char time_part[length + 1]; // Buffer to hold the date part YYYYMMDD or HHMMSSmmm
149	  // Copy the first 8 or 9 characters (YYYYMMDD) to HHMMSSmmm
150	  strncpy(time_part, time_stamp_str + shift, length);
151	  time_part[length] = '\0'; // Null-terminate the string
152	  // Convert timestamp string to integer
153	  return convert_time_stamp_to_int(time_part);
