162	// create shared memory
163	int create_shm(char **addrN, const char *shm_path, int projectId)
164	{
165	  key_t key;
166	  if (-1 != open(shm_path, O_CREAT, 0777)) {
167	    key = ftok(shm_path, projectId);
168	  } else {
169	    err_exit("Error: open shared memory");
170	  }
171	
172	  if (key < 0) {
173	    err_exit("Error: ftok error");
174	  }
175	
176	  int shm_id;
177	  shm_id = shmget(key, SHMSIZE, IPC_CREAT | IPC_EXCL | 0664);
178	  if (shm_id == -1) {
179	    if (errno == EEXIST) {
180	      printf("Error: shared memeory already exist\n");
181	      shm_id = shmget(key, 0, 0);
182	      printf("reference shm_id = %d\n", shm_id);
183	    } else {
184	      perror("errno");
185	      err_exit("shmget error");
186	    }
187	  }
188	  char *addr;
189	  // address to attach - attach for read & write
190	  if ((addr = shmat(shm_id, 0, 0)) == (void *)-1) {
191	    if (shmctl(shm_id, IPC_RMID, NULL) == -1)
192	      err_exit("Error: shmctl error");
193	    else {
194	      printf("Attach shared memory failed\n");
195	      printf("remove shared memory identifier successful\n");
196	    }
197	    err_exit("shmat error");
198	  }
199	  *addrN = addr;
200	  return shm_id;

  return shm_id;
}

// delete shared memory
void del_shm(char *addr, int shm_id)
{
  if (shmdt(addr) < 0)
    err_exit("shmdt error");

  if (shmctl(shm_id, IPC_RMID, NULL) == -1)
    err_exit("shmctl error");
  else {
    printf("Remove shared memory identifier successful\n");
  }
}

